#!/usr/bin/env python3
# RBGJL Step 06: Cloud-dispatched GAR package delete with honest in-pool LRO poll
#   + absence-verify membrane + per-version cascade fallback. Shared by banish
#   (Lode) and abjure (hallmark).
# Builder: gcr.io/cloud-builders/gcloud:latest (floating bootstrap; python3 +
#   urllib + json — the reliquary-less delete build rides this, not a pinned tool).
# Runs as Director (the build's serviceAccount — the only identity holding
#   repoAdmin/delete; Mason stays writer-only). There is no host-issued DELETE, so
#   the build's success IS the delete outcome — closing the trust-200 LRO gap.
# Substitutions (automapSubstitutions provides as env vars):
#   ${_RBGL_GAR_API_BASE} ${_RBGL_GAR_PACKAGE_BASE} ${_RBGL_DELETE_PACKAGES}
#
# For each package in the space-separated _RBGL_DELETE_PACKAGES list: issue GAR
# packages.delete, poll the returned long-running operation to terminal IN-POOL
# (the LRO verdict is advisory — absence is the truth), then VERIFY ABSENCE with a
# GET. Verified-absent is success, whatever the LRO claimed — including GAR's
# index-web cascade signature, where packages.delete auto-removes protected
# children and the LRO terminates NOT_FOUND (code 5) even though the package is
# gone (RBSCB cascade membrane). If the package SURVIVES the cascade (the web
# genuinely refuses a single packages.delete), escalate to the per-version
# fallback — delete each version with force=true, NOT_FOUND-tolerant, looping
# until empty, then delete the now-flat package shell — and verify absence again.
# A package still present after the fallback, or an unexpected error during it,
# dies loud. Already-absent on entry (DELETE -> 404) is idempotent (CBi_103).

import json
import os
import sys
import time
import urllib.error
import urllib.request


def die(msg):
    print(f"FATAL: {msg}", file=sys.stderr)
    sys.exit(1)


def require_env(name):
    val = os.environ.get(name, "")
    if not val:
        die(f"{name} missing")
    return val


METADATA_TOKEN_URL = (
    "http://metadata.google.internal/computeMetadata/v1/"
    "instance/service-accounts/default/token"
)


def metadata_token():
    """Fetch OAuth2 access token from GCE metadata server."""
    req = urllib.request.Request(METADATA_TOKEN_URL, headers={"Metadata-Flavor": "Google"})
    resp = urllib.request.urlopen(req)
    return json.loads(resp.read())["access_token"]


def gar_fetch(url, token, accept, method="GET"):
    headers = {"Authorization": f"Bearer {token}", "Accept": accept}
    req = urllib.request.Request(url, headers=headers, method=method)
    return urllib.request.urlopen(req)


def gar_json(url, token, accept):
    resp = gar_fetch(url, token, accept)
    return json.loads(resp.read())


JSON_ACCEPT = "application/json"
GAR_NOT_FOUND_CODE = 5      # google.rpc.Code.NOT_FOUND — the cascade signature
POLL_INTERVAL_SEC = 5
POLL_TIMEOUT_SEC = 240      # per-operation in-pool ceiling; host budget covers the loop
MAX_VERSION_SWEEPS = 5      # bounded fallback passes; a web that still refuses fails loud


def poll_operation(api_base, op, token):
    """Poll a GAR long-running operation to terminal in-pool. Returns the operation's
    `.error` dict on a terminal-with-error, or None on a clean terminal / non-LRO."""
    if op.get("done"):
        return op.get("error")
    name = op.get("name", "")
    if not name:
        # No operation name and not done: a non-LRO immediate completion.
        return None
    op_url = f"{api_base}/{name}"
    elapsed = 0
    while True:
        time.sleep(POLL_INTERVAL_SEC)
        elapsed += POLL_INTERVAL_SEC
        try:
            polled = gar_json(op_url, token, JSON_ACCEPT)
        except urllib.error.HTTPError as e:
            die(f"LRO poll failed for {name}: HTTP {e.code}")
        if polled.get("done"):
            return polled.get("error")
        if elapsed >= POLL_TIMEOUT_SEC:
            die(f"LRO poll timed out after {elapsed}s for operation {name}")
        print(f"  ... operation still running at {elapsed}s")


def package_absent(pkg_url, token):
    """The membrane core: True iff a GET on the package returns 404. A surviving package
    returns 200; an unexpected status dies loud."""
    try:
        gar_fetch(pkg_url, token, JSON_ACCEPT, method="GET")
    except urllib.error.HTTPError as e:
        if e.code == 404:
            return True
        die(f"Absence-verify returned unexpected HTTP {e.code}")
    return False


def delete_and_poll(api_base, url, token, label, tolerate_not_found):
    """DELETE a resource by URL and poll its LRO to terminal. With tolerate_not_found, a
    404 on the call and a NOT_FOUND (code 5) terminal LRO are both accepted — the
    resource was already removed (e.g. a child auto-removed by a parent's cascade). Any
    other terminal LRO error dies loud."""
    try:
        op = json.loads(gar_fetch(url, token, JSON_ACCEPT, method="DELETE").read())
    except urllib.error.HTTPError as e:
        if e.code == 404 and tolerate_not_found:
            return
        die(f"DELETE {label} failed: HTTP {e.code} {e.read().decode(errors='replace')}")
    error = poll_operation(api_base, op, token)
    if error is None:
        return
    if tolerate_not_found and error.get("code") == GAR_NOT_FOUND_CODE:
        return
    die(f"Delete LRO for {label} terminated with error {error.get('code')}: {error.get('message')}")


def list_versions(api_base, pkg_url, token):
    """All version IDs (the segment after /versions/) for a package, empty if gone."""
    try:
        data = gar_json(f"{pkg_url}/versions?pageSize=1000", token, JSON_ACCEPT)
    except urllib.error.HTTPError as e:
        if e.code == 404:
            return []
        die(f"versions.list failed: HTTP {e.code}")
    ids = []
    for v in data.get("versions", []):
        name = v.get("name", "")
        if "/versions/" in name:
            ids.append(name.split("/versions/", 1)[1])
    return ids


def per_version_fallback(api_base, pkg, pkg_url, token):
    """Cascade fallback: a single packages.delete left an index-web present. Delete the
    package's versions one at a time (force=true to drop their tags; NOT_FOUND-tolerant,
    since a parent's cascade may already have removed a child), looping until the
    version set is empty, then delete the now-flat package shell. Bounded so a web that
    genuinely refuses fails loud (back in the caller's final absence check)."""
    print(f"  Escalating to per-version fallback for {pkg}")
    for sweep in range(1, MAX_VERSION_SWEEPS + 1):
        version_ids = list_versions(api_base, pkg_url, token)
        if not version_ids:
            break
        print(f"  Sweep {sweep}: deleting {len(version_ids)} version(s)")
        for ver_id in version_ids:
            delete_and_poll(api_base, f"{pkg_url}/versions/{ver_id}?force=true", token,
                            f"version {ver_id}", tolerate_not_found=True)
    delete_and_poll(api_base, pkg_url, token, f"package {pkg}", tolerate_not_found=True)


def delete_package(api_base, package_base, pkg, token):
    encoded = pkg.replace("/", "%2F")
    pkg_url = f"{api_base}/{package_base}/packages/{encoded}"
    print(f"--- Deleting package: {pkg} ---")

    # Baseline: one packages.delete, polled to terminal. The LRO verdict is advisory —
    # absence is the truth — but a non-cascade error is surfaced to the log for forensics.
    try:
        op = json.loads(gar_fetch(pkg_url, token, JSON_ACCEPT, method="DELETE").read())
    except urllib.error.HTTPError as e:
        if e.code == 404:
            print("  Package already absent (404) — idempotent, nothing to delete.")
            return
        die(f"DELETE {pkg} failed: HTTP {e.code} {e.read().decode(errors='replace')}")
    error = poll_operation(api_base, op, token)
    if error is not None:
        code = error.get("code")
        if code == GAR_NOT_FOUND_CODE:
